using Microsoft.AspNetCore.SignalR;
using System.Threading.Tasks;
using T2ACore;

/// <summary>
/// 使用SignalR发送消息
/// </summary>
public class MessageHub : Hub
{
    /// <summary>
    /// 建立特定房间号的链接
    /// </summary>
    /// <param name="room">房间号</param>
    /// <returns></returns>
    public async Task OnConnected(string room)
    {
        await Groups.AddToGroupAsync(Context.ConnectionId, room);
    }

    /// <summary>
    /// 在特定房间发送消息
    /// </summary>
    /// <param name="room">房间号</param>
    /// <param name="content">消息内容</param>
    /// <returns></returns>
    public async Task SendMessage(string room, string content)
    {
        var (account, userName) = ScopeUser.GetUserAccountName();
        await Clients.Group(room).SendAsync(
            "ReceiveMessage", content, account, userName);
    }

    /// <summary>
    /// 以个人账号为房间号建立链接
    /// 若无Token则无法建立链接
    /// </summary>
    /// <returns></returns>
    public async Task OnConnectedWithAccount()
    {
        var (account, userName) = ScopeUser.GetUserAccountName();
        if (!string.IsNullOrEmpty(account))
        {
            await Groups.AddToGroupAsync(Context.ConnectionId, account);
        }
    }

    /// <summary>
    /// 为自己发送消息
    /// 若无Token则无法发送
    /// </summary>
    /// <param name="content">消息内容</param>
    /// <returns></returns>
    public async Task SendMessageToSelf(string content)
    {
        var (account, userName) = ScopeUser.GetUserAccountName();
        if (!string.IsNullOrEmpty(account))
        {
            var group = Clients.Group(account);
            if (group != null)
            {
                await group.SendAsync("ReceiveSelfMessage", content);
            }
        }
    }


    /// <summary>
    /// 给所有人发送消息
    /// </summary>
    /// <param name="content">消息内容</param>
    /// <returns></returns>
    public async Task SendMessageToAll(string content)
    {
        await Clients.All.SendAsync(content);
    }
}
